function candidate(...segments) {
  for (const segment of segments) {
    if (typeof segment !== "string") {
      throw new TypeError("Path must be a string");
    }
  }

  let hasAbsoluteBase = false;
  const collected = [];

  for (const segment of segments) {
    if (segment === "") continue;

    if (segment[0] === "/") {
      collected.length = 0;
      hasAbsoluteBase = true;
    }

    collected.push(segment);
  }

  if (!hasAbsoluteBase) {
    let cwd = "";
    if (typeof process !== "undefined" && process && typeof process.cwd === "function") {
      cwd = process.cwd();
    }

    if (typeof cwd !== "string") {
      throw new TypeError("Current working directory must be a string");
    }

    if (cwd !== "") {
      if (cwd[0] === "/") {
        hasAbsoluteBase = true;
      }
      collected.unshift(cwd);
    }
  }

  const stack = [];
  const raw = collected.join("/").split("/");

  for (const item of raw) {
    if (item === "" || item === ".") continue;

    if (item === "..") {
      if (stack.length > 0 && stack[stack.length - 1] !== "..") {
        stack.pop();
      } else if (!hasAbsoluteBase) {
        stack.push("..");
      }
    } else {
      stack.push(item);
    }
  }

  if (hasAbsoluteBase) {
    return stack.length === 0 ? "/" : "/" + stack.join("/");
  }

  return stack.length === 0 ? "." : stack.join("/");
}
